// ================= USERS TO TRACK =================
const trackedUserIds = [
  "U0766D9TWSF", // Yahya Rehman
  "U077NT392JZ", // Muhammad Abdullah
  "U08GSRF21RD", // Imran Farooq
  "U08LDDLN2LW", // Husnain Izhar
  "U0A60EPJC9K", // Awais Gillani
  "U0A61S7497G", // Aimen Aftab
  "U0A6QF7SCQK", // Abdul Wahab
  "U0A7074QFFY", // Nadir Khan
  "U0A7R01D9K9", // Aasfa alam
  "U0A9GD2KAKX"  // Muhammad Ahmad
];

// ================= HELPERS =================
function parseDateTime(str) {
  if (!str) return null;
  const [datePart, timePart] = str.split(',').map(s => s.trim());
  const [day, month, year] = datePart.split('/');
  const [hours, minutes, seconds] = timePart.split(':');
  return new Date(year, month - 1, day, hours, minutes, seconds || 0);
}

function formatAMPM(date) {
  if (!date) return null;
  const dd = String(date.getDate()).padStart(2, '0');
  const mm = String(date.getMonth() + 1).padStart(2, '0');
  const yyyy = date.getFullYear();
  let hours = date.getHours();
  const minutes = String(date.getMinutes()).padStart(2, '0');
  const ampm = hours >= 12 ? 'PM' : 'AM';
  hours = hours % 12 || 12;
  return `${dd}/${mm}/${yyyy}, ${hours}:${minutes} ${ampm}`;
}

function calculateWorkingHours(checkIn, checkOut) {
  if (!checkIn || !checkOut) return "0h 0m";
  const diffMs = checkOut - checkIn;
  const totalMinutes = Math.floor(diffMs / (1000 * 60));
  const hours = Math.floor(totalMinutes / 60);
  const minutes = totalMinutes % 60;
  return `${hours}h ${minutes}m`;
}

function formatDate(dateObj) {
  const dd = String(dateObj.getDate()).padStart(2, '0');
  const mm = String(dateObj.getMonth() + 1).padStart(2, '0');
  const yyyy = dateObj.getFullYear();
  return `${dd}/${mm}/${yyyy}`;
}

// ================= USER PROFILE MAP =================
const userProfiles = $input.all();
const userProfileMap = new Map();

for (const profile of userProfiles) {
  userProfileMap.set(profile.json.id, profile.json);
}

// ================= GET RAW RECORDS =================
let existingRecords = [];
try {
  existingRecords = $('Group Messages by User').all();
} catch (e) {
  existingRecords = [];
}

// ================= STEP 1: GROUP RECORDS PER USER =================
const userDailyMap = new Map();

for (const record of existingRecords) {
  if (!record.json || !record.json.userId) continue;

  const { userId, date, checkInTime, checkOutTime, totalBreakDuration } = record.json;
  if (!trackedUserIds.includes(userId)) continue;

  const checkIn = parseDateTime(checkInTime);
  const checkOut = parseDateTime(checkOutTime);

  if (!userDailyMap.has(userId)) {
    userDailyMap.set(userId, []);
  }

  userDailyMap.get(userId).push({
    date,
    checkIn,
    checkOut,
    checkInTime,
    checkOutTime,
    totalBreakDuration  // ✅ carry real break duration from Group Messages node
  });
}

// ================= STEP 2: MERGE SHIFTS =================
const recordMap = new Map();
const allDates = new Set();

for (const [userId, records] of userDailyMap.entries()) {
  for (let i = 0; i < records.length; i++) {
    const current = records[i];

    let baseDate = current.date;
    let checkIn = current.checkIn;
    let checkOut = current.checkOut;

    // CASE 1: Check-in exists but no checkout → find next record's checkout
    if (checkIn && !checkOut) {
      const next = records.find(r =>
        r.checkOut &&
        new Date(r.checkOut) > checkIn &&
        (new Date(r.checkOut) - checkIn) <= (1000 * 60 * 60 * 16)
      );
      if (next) {
        checkOut = next.checkOut;
        current.checkOutTime = next.checkOutTime;
      }
    }

    // CASE 2: Checkout exists but no check-in → assign to previous day
    if (!checkIn && checkOut) {
      const prev = new Date(checkOut);
      prev.setDate(prev.getDate() - 1);
      baseDate = formatDate(prev);
    }

    const key = `${userId}|${baseDate}`;

    if (!recordMap.has(key)) {
      recordMap.set(key, {
        userId,
        date: baseDate,
        checkInTime: null,
        checkOutTime: null,
        totalBreakDuration: current.totalBreakDuration || "0h 0m"  // ✅ use real value on creation
      });
    }

    const entry = recordMap.get(key);

    if (checkIn) entry.checkInTime = current.checkInTime;
    if (checkOut) entry.checkOutTime = current.checkOutTime;

    // ✅ Always update break duration if the current record has a real value
    if (current.totalBreakDuration && current.totalBreakDuration !== "0h 0m") {
      entry.totalBreakDuration = current.totalBreakDuration;
    }

    allDates.add(baseDate);
  }
}

// ================= SORT DATES =================
const sortedDates = [...allDates].sort((a, b) => {
  const [ad, am, ay] = a.split('/');
  const [bd, bm, by] = b.split('/');
  return new Date(ay, am - 1, ad) - new Date(by, bm - 1, bd);
});

// ================= FINAL OUTPUT =================
const result = [];

for (const date of sortedDates) {
  for (const userId of trackedUserIds) {

    const userProfile = userProfileMap.get(userId);

    const userName = userProfile
      ? (userProfile.real_name || userProfile.name)
      : "Unknown User";

    const userRealName = userProfile?.real_name || null;
    const userDisplayName = userProfile?.profile?.display_name || null;

    const key = `${userId}|${date}`;
    const existing = recordMap.get(key);

    if (existing) {
      let checkIn = parseDateTime(existing.checkInTime);
      let checkOut = parseDateTime(existing.checkOutTime);

      // Final overnight safety
      if (checkIn && checkOut && checkOut < checkIn) {
        checkOut.setDate(checkOut.getDate() + 1);
      }

      result.push({
        userId,
        date,
        checkInTime: formatAMPM(checkIn),
        checkOutTime: formatAMPM(checkOut),
        totalWorkingHours: calculateWorkingHours(checkIn, checkOut),
        userName,
        userRealName,
        userDisplayName,
        totalBreakDuration: existing.totalBreakDuration || "0h 0m",  // ✅ real break duration
        status: (!checkIn && !checkOut) ? "Absent" : "Present"
      });

    } else {
      // ABSENT
      result.push({
        userId,
        date,
        checkInTime: null,
        checkOutTime: null,
        totalWorkingHours: "0h 0m",
        userName,
        userRealName,
        userDisplayName,
        totalBreakDuration: "0h 0m",
        status: "Absent"
      });
    }
  }
}

return result;

const userMessagesByDate = {};

// ================= GROUP MESSAGES =================
for (const item of $input.all()) {
  const userId = item.json.user;
  const text = (item.json.text || '').toLowerCase();
  const timestamp = parseFloat(item.json.ts) * 1000;
  const msgTime = new Date(timestamp);

  // ================= SHIFT ANCHOR FIX =================
  // Messages before 6 AM belong to the previous day's shift
  // This handles overnight shifts ending at 1 AM correctly
  const shiftAnchor = new Date(msgTime.getTime() - (6 * 60 * 60 * 1000));
  const dateString = shiftAnchor.toLocaleDateString('en-GB', { timeZone: 'Asia/Karachi' });

  if (!userMessagesByDate[userId]) userMessagesByDate[userId] = {};
  if (!userMessagesByDate[userId][dateString]) userMessagesByDate[userId][dateString] = [];

  userMessagesByDate[userId][dateString].push({
    text,
    timestamp: msgTime.getTime()
  });
}

// ================= HELPERS =================
const formatPKTime = (ts) => {
  if (!ts) return null;
  const options = { timeZone: 'Asia/Karachi', hour12: false };
  return new Date(ts).toLocaleString('en-GB', options);
};

const formatDuration = (milliseconds) => {
  if (!milliseconds || milliseconds <= 0) return '0h 0m';
  const totalMinutes = Math.floor(milliseconds / 60000);
  const hours = Math.floor(totalMinutes / 60);
  const minutes = totalMinutes % 60;
  return `${hours}h ${minutes}m`;
};

// ================= MAIN =================
const output = [];

for (const userId in userMessagesByDate) {
  for (const dateString in userMessagesByDate[userId]) {

    const messages = userMessagesByDate[userId][dateString];
    messages.sort((a, b) => a.timestamp - b.timestamp);

    let checkIn = null;
    let checkOut = null;

    const stepOutStepInPairs = [];
    let currentStepOut = null;

    const allMessages = [];

    for (const msg of messages) {
      const text = msg.text;

      const isCheckIn =
        text.includes('check in') ||
        text.includes('check-in') ||
        text.includes('checked in') ||
        text === 'in';

      const isCheckOut =
        text.includes('check out') ||
        text.includes('check-out') ||
        text.includes('checked out') ||
        text === 'out';

      const isStepOut =
        text.includes('step out') ||
        text.includes('step-out') ||
        text.includes('stepped out');

      const isStepIn =
        text.includes('step in') ||
        text.includes('step-in') ||
        text.includes('stepped in');

      // Track message
      let messageType = 'unknown';
      if (isCheckIn) messageType = 'check in';
      else if (isCheckOut) messageType = 'check out';
      else if (isStepOut) messageType = 'step out';
      else if (isStepIn) messageType = 'step in';

      allMessages.push({
        type: messageType,
        text,
        timestamp: formatPKTime(msg.timestamp)
      });

      // Check-in / Check-out
      if (isCheckIn && !checkIn) checkIn = msg.timestamp;
      if (isCheckOut) checkOut = msg.timestamp;

      // Break tracking
      if (isStepOut && !currentStepOut) {
        currentStepOut = msg.timestamp;
      } 
      else if (isStepIn && currentStepOut) {
        stepOutStepInPairs.push({
          stepOut: currentStepOut,
          stepIn: msg.timestamp
        });
        currentStepOut = null;
      }
    }

    // ================= BREAK LOGIC =================

    let totalBreakDuration = 0;

    // 1. step out → step in (actual break)
    for (const pair of stepOutStepInPairs) {
      totalBreakDuration += (pair.stepIn - pair.stepOut);
    }

    // 2. step out only → +1 hour
    if (currentStepOut) {
      const ONE_HOUR = 60 * 60 * 1000;
      totalBreakDuration += ONE_HOUR;
    }

    // 3. step in only → ignored automatically

    // ================= WORK HOURS =================

    let totalWorkingHours = null;
    let workingHoursFormatted = 'N/A';

    if (checkIn) {
      const effectiveCheckOut = checkOut || messages[messages.length - 1].timestamp;

      totalWorkingHours = (effectiveCheckOut - checkIn) - totalBreakDuration;

      workingHoursFormatted = formatDuration(totalWorkingHours);
    }

    // ================= STATUS =================

    let status = 'Absent';

    if (checkIn && checkOut) {
      status = 'Complete';
    } 
    else if (checkIn && !checkOut) {
      status = 'Missing Check-out';
    } 
    else if (!checkIn && checkOut) {
      status = 'Missing Check-in';
    }

    // ================= OUTPUT =================

    output.push({
      json: {
        userId,
        date: dateString,
        checkInTime: formatPKTime(checkIn),
        checkOutTime: formatPKTime(checkOut),
        totalWorkingHours: workingHoursFormatted,
        totalBreakDuration: formatDuration(totalBreakDuration),
        allMessages,
        totalMessages: messages.length,
        status
      }
    });
  }
}

return output;

// Reference words
const checkInRef = "check in";
const checkOutRef = "check out";
const stepOutRef = "step out";
const stepInRef = "step in";

// Levenshtein similarity function
function similarity(a, b) {
    const m = a.length, n = b.length;
    const dp = Array.from({length: m+1}, () => Array(n+1).fill(0));

    for (let i = 0; i <= m; i++) dp[i][0] = i;
    for (let j = 0; j <= n; j++) dp[0][j] = j;

    for (let i = 1; i <= m; i++) {
        for (let j = 1; j <= n; j++) {
            dp[i][j] = Math.min(
                dp[i - 1][j] + 1,
                dp[i][j - 1] + 1,
                dp[i - 1][j - 1] + (a[i - 1] === b[j - 1] ? 0 : 1)
            );
        }
    }
    return 1 - dp[m][n] / Math.max(m, n);
}

// Regex for common cases
const checkInRegex = /check[- ]?in|checked[- ]?in|checkin/i;
const checkOutRegex = /check[- ]?out|checked[- ]?out|checkout/i;
const stepOutRegex = /step[- ]?out|stepped[- ]?out|stepout/i;
const stepInRegex = /step[- ]?in|stepped[- ]?in|stepin/i;

// Fuzzy threshold
const threshold = 0.7;

// Process the input dynamically
const results = [];

for (const item of $input.all()) {
    if (!item.json || !item.json.text) continue; // skip if no text

    const originalText = item.json.text;
    const textNormalized = originalText.toLowerCase().replace(/[^a-z ]/g, '');

    if (checkInRegex.test(textNormalized) || similarity(textNormalized, checkInRef) >= threshold) {
        results.push({ ...item, json: { ...item.json, text: "check in" } });
    } else if (checkOutRegex.test(textNormalized) || similarity(textNormalized, checkOutRef) >= threshold) {
        results.push({ ...item, json: { ...item.json, text: "check out" } });
    } else if (stepOutRegex.test(textNormalized) || similarity(textNormalized, stepOutRef) >= threshold) {
        results.push({ ...item, json: { ...item.json, text: "step out" } });
    } else if (stepInRegex.test(textNormalized) || similarity(textNormalized, stepInRef) >= threshold) {
        results.push({ ...item, json: { ...item.json, text: "step in" } });
    }
    // else ignore completely
}

return results;

