const results = [];

// ================= USER SHIFT CONFIG =================
const userShifts = {
  "U0766D9TWSF": { start: { h: 16, m: 0 }, end: { h: 1, m: 0 }, lateAfter: 15 }, // Yahya Rehman (4PM–1AM)
  "U077NT392JZ": { start: { h: 16, m: 0 }, end: { h: 1, m: 0 }, lateAfter: 15 },  // Muhammad Abdullah (4PM–1AM)
  "U08GSRF21RD": { start: { h: 16, m: 0 }, end: { h: 1, m: 0 }, lateAfter: 15 },  // Imran Farooq (4PM–1AM)
  "U08LDDLN2LW": { start: { h: 16, m: 0 }, end: { h: 1, m: 0 }, lateAfter: 15 },  // Husnain Izhar (4PM–1AM)
  "U0A60EPJC9K": { start: { h: 13, m: 0 }, end: { h: 22, m: 0 }, lateAfter: 15 }, // Awais Gillani (1PM–10PM)
  "U0A61S7497G": { start: { h: 13, m: 0 }, end: { h: 22, m: 0 }, lateAfter: 15 }, // Aimen Aftab (1PM–10PM)
  "U0A6QF7SCQK": { start: { h: 16, m: 0 }, end: { h: 1, m: 0 }, lateAfter: 15 },  // Abdul Wahab (4PM–1AM)
  "U0A7074QFFY": { start: { h: 16, m: 0 }, end: { h: 1, m: 0 }, lateAfter: 15 },  // Nadir Khan (4PM–1AM)
  "U0A7R01D9K9": { start: { h: 13, m: 0 }, end: { h: 22, m: 0 }, lateAfter: 15 }, // Aasfa Alam (1PM–10PM)
  "U0A9GD2KAKX": { start: { h: 16, m: 0 }, end: { h: 1, m: 0 }, lateAfter: 15 }   // Muhammad Ahmad (4PM–1AM)
};

// ================= DEFAULT SHIFT =================
const defaultShift = {
  start: { h: 13, m: 0 },
  end: { h: 22, m: 0 },
  lateAfter: 15
};

// ================= HELPERS =================
function parseTime(str) {
  const [datePart, timePart] = str.split(', ');
  const [day, month, year] = datePart.split('/');
  return new Date(`${month}/${day}/${year}, ${timePart}`);
}

function diffMinutes(start, end) {
  return Math.round((end - start) / (1000 * 60));
}

// ================= MAIN LOOP =================
for (const item of $input.all()) {
  const userId = item.json.userId;   // ✅ use userId
  const userName = item.json.userName;
  const date = item.json.date;
  const checkInTime = item.json.checkInTime;
  let checkOutTime = item.json.checkOutTime;
  const totalBreakDuration = item.json.totalBreakDuration;

  let status = 'On Time';
  let workHoursDisplay = '-';
  let breakDisplay = '-';

  if (!checkInTime) {
    status = 'Absent';
  } else {
    const checkInDate = parseTime(checkInTime);
    let checkOutDate;

    const checkInMinutes =
      checkInDate.getHours() * 60 + checkInDate.getMinutes();

    // ================= GET USER SHIFT =================
    const shift = userShifts[userId] || defaultShift;

    const shiftStartMinutes = shift.start.h * 60 + shift.start.m;
    const lateThreshold = shiftStartMinutes + shift.lateAfter;

    // ================= STATUS =================
    if (checkInMinutes >= lateThreshold) {
      status = 'Late';
    }

    // ================= CHECKOUT LOGIC =================
    if (!checkOutTime) {
      checkOutDate = new Date(checkInDate);

      // Night shift (end < start → next day)
      if (shift.end.h < shift.start.h) {
        checkOutDate.setDate(checkOutDate.getDate() + 1);
      }

      checkOutDate.setHours(shift.end.h, shift.end.m, 0, 0);
    } else {
      checkOutDate = parseTime(checkOutTime);
    }

    // ================= WORK HOURS =================
    let totalMinutes = diffMinutes(checkInDate, checkOutDate);

    // ================= BREAK CONVERSION =================
    let breakMinutes = 0;

    if (totalBreakDuration && typeof totalBreakDuration === 'string') {
      const match = totalBreakDuration.match(/(\d+)h\s*(\d+)m/);
      if (match) {
        const h = parseInt(match[1]) || 0;
        const m = parseInt(match[2]) || 0;
        breakMinutes = h * 60 + m;
      }
    }

    // Subtract break
    totalMinutes = Math.max(0, totalMinutes - breakMinutes);

    // ================= FORMAT =================
    const h = Math.floor(totalMinutes / 60);
    const m = totalMinutes % 60;

    workHoursDisplay = `${h}h ${m}m`;

    if (!totalBreakDuration || totalBreakDuration === '0h 0m') {
      breakDisplay = 'No Break';
    } else {
      breakDisplay = totalBreakDuration;
    }
  }

  results.push({
    json: {
      Name: userName,
      Date: date,
      "Check-In": checkInTime || '-',
      "Check-Out": checkOutTime || '-',
      "Work Hours": workHoursDisplay,
      Break: breakDisplay,
      Status: status,
    },
  });
}

return results;

// ================= HELPERS =================

const messagesBelow7Hours = [
  "⚠️ Critical Low",
  "🚨 Very Low",
  "⛔ Low Hours",
  "❗ Urgent Fix",
  "📉 Poor Attendance"
];

const messages7To20Hours = [
  "⚠️ Needs Improvement",
  "📉 Below Target",
  "🔧 Improve Hours",
  "⏳ Low Progress",
  "📊 Under Target"
];

const messages20To30Hours = [
  "👍 Good Progress",
  "📈 On Track",
  "💪 Keep Going",
  "⚡ Building Momentum",
  "🌟 Decent Effort"
];

const messages30To35Hours = [
  "🚀 Almost There",
  "🎯 Near Target",
  "💯 Close Goal",
  "🔥 Strong Effort",
  "⭐ Great Progress"
];

const messages35To40Hours = [
  "🏆 Excellent Work",
  "⭐ Top Effort",
  "💎 Nearly Perfect",
  "📈 High Performance",
  "🔥 Outstanding"
];

const messages40PlusHours = [
  "🏆 Perfect Week",
  "👑 Elite Performance",
  "💯 Goal Achieved",
  "🚀 Above Target",
  "🌟 Top Performer"
];

// ================= HELPERS =================

function getRandomMessage(arr, hours, remaining, percentage) {
  let msg = arr[Math.floor(Math.random() * arr.length)];
  return msg
    .replace("{hours}", hours)
    .replace("{remaining}", remaining)
    .replace("{percentage}", percentage);
}

function getDayName(dateStr) {
  if (!dateStr || typeof dateStr !== "string") return null;

  const parts = dateStr.split("/");
  if (parts.length !== 3) return null;

  const [d, m, y] = parts.map(Number);
  const date = new Date(Date.UTC(y, m - 1, d));

  if (isNaN(date)) return null;

  return date.toLocaleDateString("en-US", { weekday: "short" });
}

function extractMinutes(str) {
  if (!str || str === "-" || str === "No Break") return 0;

  const h = str.match(/(\d+)\s*h/);
  const m = str.match(/(\d+)\s*m/);

  return (h ? +h[1] : 0) * 60 + (m ? +m[1] : 0);
}

// ================= STATUS =================

function normalizeStatus(status, checkOut, minutes) {
  if (!status || status === "Absent") return "Absent";
  if (status === "Late" && (!checkOut || checkOut === "-")) return "Late + Missing";
  if (!checkOut || checkOut === "-") return "Missing Check-out";
  if (minutes === 0) return "Absent";
  if (status === "Late") return "Late";
  return "On Time";
}

// ================= CELL FORMAT =================

function formatCell(status, h, m) {
  const total = h * 60 + m;
  const label = `${h}h ${m}m`;

  if (status === "Absent") return "- (A)";

  let emoji = "🟢";
  if (total < 420) emoji = "🔴";
  else if (total < 480) emoji = "🟡";

  if (status === "Late") return `${emoji} ${label} (L)`;
  if (status === "Missing Check-out") return `${emoji} ${label} (M)`;
  if (status === "Late + Missing") return `${emoji} ${label} (L,M)`;

  return `${emoji} ${label}`;
}

function formatHours(min) {
  return `${Math.floor(min / 60)}h ${min % 60}m`;
}

// ================= MAIN =================

const table = {};
const days = ["Mon", "Tue", "Wed", "Thu", "Fri"];

let totalEmployees = new Set();
let totalLate = 0;
let totalOnTime = 0;
let totalMissingCheckout = 0;
let totalAbsent = 0;

for (const item of $input.all()) {
  const d = item.json;

  const name = d.Name;
  const date = d.Date;
  const statusRaw = d.Status;
  const checkIn = d["Check-In"];
  const checkOut = d["Check-Out"];
  const work = d["Work Hours"];

  if (!name) continue;

  totalEmployees.add(name);

  const minutes = extractMinutes(work);
  const h = Math.floor(minutes / 60);
  const m = minutes % 60;

  const day = getDayName(date);
  if (!day) continue;

  const status = normalizeStatus(statusRaw, checkOut, minutes);
  const cell = formatCell(status, h, m);

  if (!table[name]) {
    table[name] = {
      Employee: name,
      Mon: "",
      Tue: "",
      Wed: "",
      Thu: "",
      Fri: "",
      totalMinutes: 0
    };
  }

  const prev = table[name][day + "_min"] || 0;

  table[name].totalMinutes =
    (table[name].totalMinutes || 0) - prev + minutes;

  table[name][day] = cell;
  table[name][day + "_min"] = minutes;

  // ================= COUNTERS =================

  if (status === "Late") totalLate++;
  if (status === "On Time") totalOnTime++;
  if (status === "Absent") totalAbsent++;

  const hasCheckIn = checkIn && checkIn !== "-";
  const hasCheckOut = checkOut && checkOut !== "-";

  if (hasCheckIn && !hasCheckOut) {
    totalMissingCheckout++;
  }
}

// ================= FILL MISSING DAYS =================

for (const name in table) {
  for (const d of days) {
    if (!table[name][d]) {
      table[name][d] = "- (A)";
    }
  }
}

// ================= SUMMARY =================

const employeesSummary = Object.values(table).map(row => {
  const totalMin = row.totalMinutes || 0;
  const weekly = totalMin / 60;

  const remaining = (40 - weekly).toFixed(1);
  const percent = ((weekly / 40) * 100).toFixed(0);

  let msg = "";

  if (weekly < 7)
    msg = getRandomMessage(messagesBelow7Hours, weekly.toFixed(1), remaining, percent);
  else if (weekly < 20)
    msg = getRandomMessage(messages7To20Hours, weekly.toFixed(1), remaining, percent);
  else if (weekly < 30)
    msg = getRandomMessage(messages20To30Hours, weekly.toFixed(1), remaining, percent);
  else if (weekly < 35)
    msg = getRandomMessage(messages30To35Hours, weekly.toFixed(1), remaining, percent);
  else if (weekly < 40)
    msg = getRandomMessage(messages35To40Hours, weekly.toFixed(1), remaining, percent);
  else
    msg = getRandomMessage(messages40PlusHours, weekly.toFixed(1), remaining, percent);

  const {
    totalMinutes,
    Mon_min,
    Tue_min,
    Wed_min,
    Thu_min,
    Fri_min,
    ...clean
  } = row;

  return {
    ...clean,
    totalHours: formatHours(totalMin),
    messageToSend: msg
  };
});

